<?php declare(strict_types=1); require_once dirname(__DIR__) . '/config/bootstrap.php'; ns_redirect_legacy_url('/ferramentas/calculadora-cagr'); ns_render_page_start('tool:calculadora-cagr'); ?>
<main><div class="tool-page"><nav class="breadcrumb" aria-label="Navegação breadcrumb"><a href="<?= ns_escape(ns_href('/')) ?>">Início</a><span class="sep">›</span><a href="<?= ns_escape(ns_href('/ferramentas')) ?>">Ferramentas</a><span class="sep">›</span><span>Calculadora de CAGR</span></nav><?php ns_render_ad_slot('leaderboard'); ?><div class="tool-header"><div class="tool-page-icon" style="background:linear-gradient(135deg,#eef8ff,#d9e9ff);">📊</div><div><h1>Calculadora de CAGR</h1><p>Descubra a taxa composta de crescimento anual para investimentos, receita, base de clientes e outras séries.</p><span class="tag tag-blue">Finanças</span></div></div><div class="tool-box"><div class="form-row"><div class="form-group"><label for="cagr-inicial">Valor inicial</label><input id="cagr-inicial" class="form-control" type="number" min="0" step="0.01"></div><div class="form-group"><label for="cagr-final">Valor final</label><input id="cagr-final" class="form-control" type="number" min="0" step="0.01"></div><div class="form-group"><label for="cagr-anos">Anos</label><input id="cagr-anos" class="form-control" type="number" min="1" step="1"></div></div><div class="form-row"><button class="btn btn-primary" type="button" onclick="calcCAGR()">Calcular CAGR</button><button class="btn btn-outline" type="button" onclick="clearCAGR()">Limpar</button><button class="copy-btn" type="button" onclick="copyCAGR(this)">Copiar resultado</button></div><div class="notice notice-warn" id="cagr-erro" style="display:none;"><span>⚠️</span><span id="cagr-erro-texto"></span></div><div class="result-box" id="cagr-res"><div class="result-grid"><div class="result-item"><div class="label">CAGR</div><div class="value" id="cagr-taxa-res">—</div></div><div class="result-item"><div class="label">Multiplicação total</div><div class="value" id="cagr-mult-res">—</div></div></div><div id="cagr-det" style="margin-top:1rem;color:var(--text2);"></div></div></div><?php ns_render_ad_slot('rectangle'); ?><div class="seo-content"><h2>O que é essa ferramenta</h2><p>CAGR é a taxa composta de crescimento anual. Ela mostra qual seria a taxa média anual necessária para sair de um valor inicial e chegar a um valor final ao longo de um período.</p><h2>Como usar</h2><p>Informe valor inicial, valor final e quantidade de anos. A ferramenta aplica a fórmula composta e retorna o percentual anualizado.</p><h2>Exemplo de uso</h2><p>Se um investimento cresce de 10.000 para 20.000 em 5 anos, o CAGR indica a taxa média anual equivalente desse crescimento total.</p><h2>Perguntas frequentes</h2><h3>CAGR é a mesma coisa que média simples?</h3><p>Não. Ele considera crescimento composto.</p><h3>Serve para receita e usuários?</h3><p>Sim. Pode ser usado em vários tipos de série temporal.</p><h3>Posso usar com queda?</h3><p>Sim, se o valor final for menor, a taxa anual será negativa.</p></div></div></main><script>const cagrI=document.getElementById('cagr-inicial'),cagrF=document.getElementById('cagr-final'),cagrA=document.getElementById('cagr-anos'); function cagrErr(m){document.getElementById('cagr-erro-texto').textContent=m;document.getElementById('cagr-erro').style.display='flex';document.getElementById('cagr-res').classList.remove('show')} function cagrClearErr(){document.getElementById('cagr-erro').style.display='none'} function calcCAGR(){const i=parseFloat(cagrI.value),f=parseFloat(cagrF.value),a=parseInt(cagrA.value||'0',10);cagrClearErr();if(isNaN(i)||isNaN(f)||isNaN(a)||i<=0||f<=0||a<=0){cagrErr('Informe valores válidos e maiores que zero.');return}const taxa=(Math.pow(f/i,1/a)-1)*100;document.getElementById('cagr-taxa-res').textContent=fmtNum(taxa,2)+'%';document.getElementById('cagr-mult-res').textContent=fmtNum(f/i,2)+'x';document.getElementById('cagr-det').textContent='Taxa anual composta equivalente para o período informado.';showResult('cagr-res')} function clearCAGR(){cagrI.value='';cagrF.value='';cagrA.value='';document.getElementById('cagr-res').classList.remove('show');cagrClearErr()} function copyCAGR(b){if(!document.getElementById('cagr-res').classList.contains('show')){cagrErr('Calcule antes de copiar.');return}copyToClipboard('CAGR: '+document.getElementById('cagr-taxa-res').textContent,b)}</script><?php ns_render_page_end(); ?>
